import React, { useState, useCallback, useEffect, useRef } from 'react';
import { CopyIcon, CheckIcon, SaveIcon, ChevronDownIcon } from './Icons';
import { ReportOutput } from '../services/logProcessor';
import { jsPDF } from 'jspdf';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import * as XLSX from 'xlsx';

interface ReportDisplayProps {
    reportOutput: ReportOutput;
}

const downloadBlob = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
};

export const ReportDisplay: React.FC<ReportDisplayProps> = ({ reportOutput }) => {
    const { reportString, reportData } = reportOutput;
    const [copied, setCopied] = useState(false);
    const [isSaveMenuOpen, setIsSaveMenuOpen] = useState(false);
    const saveMenuRef = useRef<HTMLDivElement>(null);

    const getTimestamp = () => {
        const now = new Date();
        return `${now.getFullYear()}-${(now.getMonth() + 1).toString().padStart(2, '0')}-${now.getDate().toString().padStart(2, '0')}`;
    };

    const handleCopy = useCallback(() => {
        navigator.clipboard.writeText(reportString).then(() => {
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        });
    }, [reportString]);

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (saveMenuRef.current && !saveMenuRef.current.contains(event.target as Node)) {
                setIsSaveMenuOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const createSaveHandler = (format: 'txt' | 'pdf' | 'csv' | 'docx' | 'xlsx') => async () => {
        setIsSaveMenuOpen(false);
        const filename = `error-report-${getTimestamp()}.${format}`;

        if (format === 'txt') {
            const blob = new Blob([reportString], { type: 'text/plain' });
            downloadBlob(blob, filename);
        } else if (format === 'pdf') {
            const doc = new jsPDF();
            doc.setFont('courier', 'normal');
            doc.setFontSize(10);
            const lines = doc.splitTextToSize(reportString, 180);
            doc.text(lines, 10, 10);
            doc.save(filename);
        } else if (format === 'csv' || format === 'xlsx') {
            const data = [];
            for (const errorMessage in reportData) {
                for (const file in reportData[errorMessage]) {
                    for (const error of reportData[errorMessage][file]) {
                        data.push({
                            'Error Message': errorMessage,
                            'Filename': file,
                            'Line Number': error.lineNumber,
                            'Row Data': error.rowData,
                        });
                    }
                }
            }
            const worksheet = XLSX.utils.json_to_sheet(data);
            if (format === 'csv') {
                const csvOutput = XLSX.utils.sheet_to_csv(worksheet);
                const blob = new Blob([csvOutput], { type: 'text/csv;charset=utf-8;' });
                downloadBlob(blob, filename);
            } else {
                 const workbook = XLSX.utils.book_new();
                 XLSX.utils.book_append_sheet(workbook, worksheet, 'Errors');
                 XLSX.writeFile(workbook, filename);
            }
        } else if (format === 'docx') {
            const children: (Paragraph)[] = [];
             for (const errorMessage in reportData) {
                children.push(new Paragraph({ heading: HeadingLevel.HEADING_1, text: `Error: ${errorMessage}` }));
                for (const filename in reportData[errorMessage]) {
                    children.push(new Paragraph({ heading: HeadingLevel.HEADING_2, text: `File: ${filename}` }));
                    for (const error of reportData[errorMessage][filename]) {
                         children.push(new Paragraph({
                            children: [
                                new TextRun({ text: `  Line ${error.lineNumber}: `, bold: true }),
                                new TextRun(error.rowData),
                            ],
                            style: "wellSpaced"
                        }));
                    }
                }
            }
            const doc = new Document({ sections: [{ children }] });
            const blob = await Packer.toBlob(doc);
            downloadBlob(blob, filename);
        }
    };


    return (
        <div className="relative bg-slate-50 dark:bg-slate-900/70 rounded-lg shadow-inner">
            <div className="absolute top-3 right-3 flex items-center space-x-2">
                <div className="relative" ref={saveMenuRef}>
                    <button
                        onClick={() => setIsSaveMenuOpen(prev => !prev)}
                        className="flex items-center px-3 py-1 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-md hover:bg-slate-300 dark:hover:bg-slate-600 transition text-sm"
                        aria-label="Open save options"
                    >
                        <SaveIcon className="w-4 h-4 mr-2" />
                        <span>Save as...</span>
                        <ChevronDownIcon className="w-4 h-4 ml-1" />
                    </button>
                    {isSaveMenuOpen && (
                        <div className="absolute right-0 mt-2 w-32 bg-white dark:bg-slate-800 rounded-md shadow-lg z-10 border border-slate-200 dark:border-slate-700">
                            <ul className="py-1 text-sm text-slate-700 dark:text-slate-200">
                                <li><button onClick={createSaveHandler('txt')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">TXT</button></li>
                                <li><button onClick={createSaveHandler('pdf')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">PDF</button></li>
                                <li><button onClick={createSaveHandler('csv')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">CSV</button></li>
                                <li><button onClick={createSaveHandler('xlsx')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">XLSX</button></li>
                                <li><button onClick={createSaveHandler('docx')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">DOCX</button></li>
                            </ul>
                        </div>
                    )}
                </div>

                <button
                    onClick={handleCopy}
                    className="flex items-center px-3 py-1 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-md hover:bg-slate-300 dark:hover:bg-slate-600 transition text-sm"
                    aria-label="Copy report to clipboard"
                >
                    {copied ? (
                        <>
                            <CheckIcon className="w-4 h-4 mr-2 text-green-500" /> Copied!
                        </>
                    ) : (
                        <>
                            <CopyIcon className="w-4 h-4 mr-2" /> Copy
                        </>
                    )}
                </button>
            </div>
            <pre className="p-4 pt-12 text-xs md:text-sm font-mono whitespace-pre-wrap break-words overflow-x-auto max-h-[60vh]">
                <code>
                    {reportString}
                </code>
            </pre>
        </div>
    );
};

import { ParsedLogError, ReportData } from '../types';

export interface ReportOutput {
    reportString: string;
    reportData: ReportData;
    warnings: string[];
}

const DESCRIPTION_REGEX = /(?<error_msg>.*?), file:\s*(?<filename>.*?)\s*\(Lines:\s*(?<lines>[\d,\s]+)\)/;

const readFileAsText = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = () => reject(reader.error);
        reader.readAsText(file);
    });
};

const parseLogCsv = (logContent: string): ParsedLogError[] => {
    const lines = logContent.trim().split(/\r?\n/);
    if (lines.length < 2) return [];

    const header = lines[0].split(';').map(h => h.trim().replace(/"/g, ''));
    const stateIndex = header.indexOf('State');
    const descriptionIndex = header.indexOf('Description');

    if (stateIndex === -1 || descriptionIndex === -1) {
        throw new Error('Log CSV is missing required "State" or "Description" columns.');
    }

    const errors: ParsedLogError[] = [];

    for (let i = 1; i < lines.length; i++) {
        // A simple split is sufficient based on the specified format.
        const values = lines[i].split(';').map(v => v.trim().replace(/"/g, ''));
        if (values[stateIndex] === 'Error') {
            const description = values[descriptionIndex];
            const match = description.match(DESCRIPTION_REGEX);

            if (match && match.groups) {
                const { error_msg, filename, lines } = match.groups;
                const parsedLines = lines.split(',')
                    .map(l => parseInt(l.trim(), 10))
                    .filter(n => !isNaN(n));

                if (parsedLines.length > 0) {
                    errors.push({
                        errorMessage: error_msg.trim(),
                        filename: filename.trim(),
                        lines: parsedLines,
                    });
                }
            }
        }
    }
    return errors;
};

const formatReport = (reportData: ReportData, warnings: string[]): string => {
    let reportString = '';
    const now = new Date();
    const timestamp = `${now.getFullYear()}-${(now.getMonth() + 1).toString().padStart(2, '0')}-${now.getDate().toString().padStart(2, '0')} ${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

    reportString += `==================================================\n`;
    reportString += `ERROR REPORT GENERATED ON [${timestamp}]\n`;
    reportString += `==================================================\n\n`;

    if (warnings.length > 0) {
        reportString += `WARNINGS:\n`;
        warnings.forEach(w => {
            reportString += `- ${w}\n`;
        });
        reportString += `--------------------------------------------------\n\n`;
    }

    if (Object.keys(reportData).length === 0) {
        reportString += 'No reconcilable errors found in the provided files.\n';
        return reportString;
    }

    for (const errorMessage in reportData) {
        reportString += `[ERROR TYPE]: "${errorMessage}"\n`;
        reportString += `--------------------------------------------------\n`;
        const files = reportData[errorMessage];
        for (const filename in files) {
            reportString += `File: ${filename}\n`;
            const reconciledErrors = files[filename];
            reconciledErrors.forEach(({ lineNumber, rowData }) => {
                reportString += `  Line ${lineNumber}:  ${rowData}\n`;
            });
            reportString += `\n`;
        }
    }
    return reportString;
};

export const generateReport = async (logFile: File, sourceFiles: FileList): Promise<ReportOutput> => {
    const logContent = await readFileAsText(logFile);
    const parsedErrors = parseLogCsv(logContent);

    const errorsByFile = parsedErrors.reduce((acc, error) => {
        if (!acc[error.filename]) {
            acc[error.filename] = [];
        }
        acc[error.filename].push(error);
        return acc;
    }, {} as { [filename: string]: ParsedLogError[] });

    const sourceFileMap = new Map<string, File>();
    for (let i = 0; i < sourceFiles.length; i++) {
        sourceFileMap.set(sourceFiles[i].name, sourceFiles[i]);
    }

    const reportData: ReportData = {};
    const warnings: string[] = [];

    for (const filename in errorsByFile) {
        const sourceFile = sourceFileMap.get(filename);
        if (!sourceFile) {
            warnings.push(`Source file "${filename}" mentioned in the log was not found.`);
            continue;
        }

        try {
            const sourceContent = await readFileAsText(sourceFile);
            const sourceLines = sourceContent.trim().split(/\r?\n/);
            const fileErrors = errorsByFile[filename];

            fileErrors.forEach(error => {
                if (!reportData[error.errorMessage]) {
                    reportData[error.errorMessage] = {};
                }
                if (!reportData[error.errorMessage][filename]) {
                    reportData[error.errorMessage][filename] = [];
                }

                error.lines.forEach(lineNumber => {
                    // Indexing adjustment: Log line numbers are 1-based.
                    // Pandas index is 0-based. Line 1 is header, so Line 2 in file is index 0.
                    // Target Index = Log Line Number - 2
                    const dataIndex = lineNumber - 2;
                    if (dataIndex >= 0 && dataIndex < sourceLines.length) {
                        reportData[error.errorMessage][filename].push({
                            lineNumber,
                            rowData: sourceLines[dataIndex].trim(),
                        });
                    }
                });
            });

        } catch (e) {
            if (e instanceof Error) {
                warnings.push(`Could not read or process source file "${filename}": ${e.message}`);
            }
        }
    }

    const reportString = formatReport(reportData, warnings);

    return { reportString, reportData, warnings };
};

