// ... in services/logProcessor.ts

const parseLogCsv = (logContent: string): ParsedLogError[] => {
    // ... setup is the same ...
    const DETAILED_ERROR_REGEX = /(?<error_msg>.*?),\s*[Ff]ile:\s*(?<filename>.*?)\s*\([Ll]ines?:\s*(?<lines>[\d,\s-]+)\)|(?<generic_error>.*?)$/;

    const parseLineNumbers = (linesStr: string): number[] => {
        const numbers: Set<number> = new Set();
        const lineParts = linesStr.split(',').map(part => part.trim());

        for (const part of lineParts) {
            if (part.includes('-')) {
                const [startStr, endStr] = part.split('-').map(str => str.trim());
                const start = parseInt(startStr, 10);
                const end = parseInt(endStr, 10);

                if (!isNaN(start) && !isNaN(end) && start <= end) {
                    for (let i = start; i <= end; i++) {
                        numbers.add(i);
                    }
                }
            } else {
                const num = parseInt(part, 10);
                if (!isNaN(num)) {
                    numbers.add(num);
                }
            }
        }
        return Array.from(numbers).sort((a, b) => a - b);
    };

    const lines = logContent.split('\n');
    const errors: ParsedLogError[] = [];

    for (let i = 1; i < lines.length; i++) {
        const values = lines[i].split(';').map(v => v.trim().replace(/" /g, ''));
        if (values[stateIndex] === 'Error') {
            const description = values[descriptionIndex];
            const match = description.match(DETAILED_ERROR_REGEX);

            if (match) {
                if (match.groups) {
                    if (match.groups.error_msg) {
                        const { error_msg, filename, lines } = match.groups;
                        let parsedLines: number[] = [];

                        if (lines) {
                            parsedLines = parseLineNumbers(lines);
                        }
                        errors.push({
                            errorMessage: error_msg.trim(),
                            filename: filename ? filename.trim() : 'N/A',
                            lines: parsedLines,
                        });
                    } else if (match.groups.generic_error) {
                        errors.push({
                            errorMessage: match.groups.generic_error.trim(),
                            filename: 'N/A',
                            lines: [0], // Or some other default, e.g. -1.
                        });
                    }
                }
            } else {
                // Handle cases where the line doesn't match the regex at all.
                errors.push({
                    errorMessage: description.trim(),
                    filename: 'N/A',
                    lines: [0], // or a special value like -1 or -99
                });
            }
        }
    }
    return errors;
};
```


