            if (format === 'csv') {
                const csvOutput = XLSX.utils.sheet_to_csv(worksheet);
                const blob = new Blob([csvOutput], { type: 'text/csv;charset=utf-8;' });
                downloadBlob(blob, filename);
            } else {
                 const workbook = XLSX.utils.book_new();
                 XLSX.utils.book_append_sheet(workbook, worksheet, 'Errors');
                 XLSX.writeFile(workbook, filename);
            }
        } else if (format === 'docx') {
            const children: (Paragraph)[] = [];

            if (warnings.length > 0) {
                children.push(new Paragraph({ heading: HeadingLevel.HEADING_1, text: "Warnings", spacing: { after: 200 } }));
                warnings.forEach(w => children.push(new Paragraph({ text: `- ${w}`, style: "ListParagraph" })));
                children.push(new Paragraph("")); // Spacer
            }

            if (Object.keys(reportData).length > 0) {
                for (const errorMessage in reportData) {
                    children.push(new Paragraph({ heading: HeadingLevel.HEADING_1, text: `Error: ${errorMessage}`, spacing: { after: 200 } }));
                    for (const filename in reportData[errorMessage]) {
                        children.push(new Paragraph({ heading: HeadingLevel.HEADING_2, text: `File: ${filename}`, spacing: { after: 100 } }));
                        const reconciledErrors = reportData[errorMessage][filename];
                        if (reconciledErrors.length > 0) {
                            for (const error of reconciledErrors) {
                                children.push(new Paragraph({
                                    children: [
                                        new TextRun({ text: `  Line ${error.lineNumber}: `, bold: true }),
                                        new TextRun(error.rowData),
                                    ],
                                    spacing: { after: 80 }
                                }));
                            }
                        } else if (filename === 'General Error') {
                            children.push(new Paragraph({
                                children: [ new TextRun({ text: `  (This is a general error with no specific file or line number.)`, italics: true }) ],
                                spacing: { after: 80 }
                            }));
                        }
                    }
                }
            }

            if (children.length === 0) {
                children.push(new Paragraph({ text: "No reconcilable errors found in the provided files." }));
            }

            const doc = new Document({ 
                sections: [{ children }],
                styles: {
                    paragraphStyles: [{
                        id: "ListParagraph",
                        name: "List Paragraph",
                        basedOn: "Normal",
                        quickFormat: true,
                        paragraph: {
                            indent: { left: 720 }, // 0.5 inch indent
                        },
                    }],
                },
            });
            const blob = await Packer.toBlob(doc);
            downloadBlob(blob, filename);
        }
    };


    return (
        <div className="relative bg-slate-50 dark:bg-slate-900/70 rounded-lg shadow-inner overflow-hidden">
            <div className="absolute top-3 right-3 flex items-center space-x-2 z-20">
                <div className="relative" ref={saveMenuRef}>
                    <button
                        onClick={() => setIsSaveMenuOpen(prev => !prev)}
                        className="flex items-center px-3 py-1 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-md hover:bg-slate-300 dark:hover:bg-slate-600 transition text-sm"
                        aria-label="Open save options"
                    >
                        <SaveIcon className="w-4 h-4 mr-2" />
                        <span>Save as...</span>
                        <ChevronDownIcon className="w-4 h-4 ml-1" />
                    </button>
                    {isSaveMenuOpen && (
                        <div className="absolute right-0 mt-2 w-32 bg-white dark:bg-slate-800 rounded-md shadow-lg z-10 border border-slate-200 dark:border-slate-700">
                            <ul className="py-1 text-sm text-slate-700 dark:text-slate-200">
                                <li><button onClick={createSaveHandler('txt')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">TXT</button></li>
                                <li><button onClick={createSaveHandler('pdf')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">PDF</button></li>
                                <li><button onClick={createSaveHandler('csv')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">CSV</button></li>
                                <li><button onClick={createSaveHandler('xlsx')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">XLSX</button></li>
                                <li><button onClick={createSaveHandler('docx')} className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-700">DOCX</button></li>
                            </ul>
                        </div>
                    )}
                </div>

                <button
                    onClick={handleCopy}
                    className="flex items-center px-3 py-1 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-md hover:bg-slate-300 dark:hover:bg-slate-600 transition text-sm"
                    aria-label="Copy report to clipboard"
                >
                    {copied ? (
                        <>
                            <CheckIcon className="w-4 h-4 mr-2 text-green-500" /> Copied!
                        </>
                    ) : (
                        <>
                            <CopyIcon className="w-4 h-4 mr-2" /> Copy
                        </>
                    )}
                </button>
            </div>
            <div className="pt-12 max-h-[60vh] overflow-y-auto">
                 {warnings && warnings.length > 0 && (
                    <Collapsible 
                        title={<span className="text-amber-600 dark:text-amber-400">Warnings</span>} 
                        defaultOpen={true}
                        count={warnings.length}
                    >
                        <div className="py-2 pr-4 text-xs md:text-sm space-y-2" style={{ paddingLeft: '2.25rem' }}>
                            {warnings.map((warning, index) => (
                                <p key={index} className="text-slate-600 dark:text-slate-400">{warning}</p>
                            ))}
                        </div>
                    </Collapsible>
                 )}
                 {Object.keys(reportData).length === 0 && warnings.length === 0 && (
                    <div className="p-4 text-center text-slate-500">No reconcilable errors found in the provided files.</div>
                 )}
                 {Object.entries(reportData).map(([errorMessage, files], errorIndex) => {
                     const totalErrors = Object.values(files).reduce((acc, fileErrors) => acc + (fileErrors.length || 1), 0);
                     return (
                        <Collapsible 
                            key={errorIndex} 
                            title={<span><span className="font-light text-slate-500 mr-2">ERROR:</span> {errorMessage}</span>}
                            count={totalErrors}
                        >
                            {Object.entries(files).map(([filename, reconciledErrors], fileIndex) => (
                                <Collapsible 
                                    key={`${errorIndex}-${fileIndex}`} 
                                    level={1} 
                                    title={
                                        filename === 'General Error'
                                        ? <span className="italic text-amber-600 dark:text-amber-400">General Error</span>
                                        : <span><span className="font-light text-slate-500 mr-2">File:</span> {filename}</span>
                                    }
                                    count={reconciledErrors.length > 0 ? reconciledErrors.length : undefined}
                                >
                                    {filename === 'General Error' ? (
                                        <div className="text-slate-500 dark:text-slate-400 italic px-4 py-2 text-xs md:text-sm" style={{ paddingLeft: '3.5rem' }}>This is a general error with no specific file or line number.</div>
                                    ) : (
                                        <div className="font-mono text-xs md:text-sm space-y-1 py-2 pr-4" style={{ paddingLeft: '2.25rem' }}>
                                            {reconciledErrors.map(({ lineNumber, rowData }, index) => (
                                                <div key={index} className="flex hover:bg-slate-100 dark:hover:bg-slate-800/50 rounded p-1">
                                                    <span className="w-16 text-right pr-4 text-slate-400 dark:text-slate-500 select-none">{lineNumber}:</span>
                                                    <code className="flex-1 whitespace-pre-wrap break-all text-slate-700 dark:text-slate-300">{rowData}</code>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </Collapsible>
                            ))}
                        </Collapsible>
                     )
                 })}
            </div>
        </div>
    );
};

import { ParsedLogError, ReportData } from '../types';

export interface ReportOutput {
    reportString: string;
    reportData: ReportData;
    warnings: string[];
}

// This regex has been updated to be less strict:
// 1. The end-of-string anchor `$` has been removed to handle truncated lines.
// 2. The closing parenthesis `\)` is now optional `\)?` to match incomplete patterns.
const DESCRIPTION_REGEX = /(?<error_msg>.*?)(?:,)?\s*(?:[Ff]ile:?)?\s*(?<filename>\S+\.csv)\s*\([Ll]ine(?:s)?:?\s*(?<lines>[\d,\s-]+)\)?/;

const readFileAsText = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = () => reject(reader.error);
        reader.readAsText(file);
    });
};

const parseLineNumbers = (linesStr: string): number[] => {
    const numbers: Set<number> = new Set();
    // Split by comma only, to correctly handle ranges with spaces like "5 - 10".
    const parts = linesStr.split(','); 
    for (const part of parts) {
        const trimmedPart = part.trim();
        if (!trimmedPart) continue;

        if (trimmedPart.includes('-')) {
            const [start, end] = trimmedPart.split('-').map(n => parseInt(n.trim(), 10));
            if (!isNaN(start) && !isNaN(end) && end >= start) {
                for (let i = start; i <= end; i++) {
                    numbers.add(i);
                }
            }
        } else {
            const num = parseInt(trimmedPart, 10);
            if (!isNaN(num)) {
                numbers.add(num);
            }
        }
    }
    return Array.from(numbers).sort((a, b) => a - b);
};

const parseLogCsv = (logContent: string): { errors: ParsedLogError[], warnings: string[] } => {
    const lines = logContent.trim().split(/\r?\n/);
    if (lines.length < 2) return { errors: [], warnings: [] };

    // A robust CSV row parser that handles quoted fields containing the delimiter.
    const parseCsvRow = (row: string): string[] => {
        // This regex splits by semicolon, but ignores semicolons inside double-quoted strings.
        return row.split(/;(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(v => {
            let value = v.trim();
            // Remove surrounding quotes if they exist
            if (value.startsWith('"') && value.endsWith('"')) {
                value = value.substring(1, value.length - 1);
            }
            // Replace escaped double quotes "" with a single quote "
            return value.replace(/""/g, '"');
        });
    };

    const header = parseCsvRow(lines[0]);
    const stateIndex = header.indexOf('State');
    const descriptionIndex = header.indexOf('Description');

    if (stateIndex === -1 || descriptionIndex === -1) {
        throw new Error('Log CSV is missing required "State" or "Description" columns.');
    }

    const errors: ParsedLogError[] = [];
    const warnings: string[] = [];

    for (let i = 1; i < lines.length; i++) {
        const row = lines[i];
        if (!row.trim()) continue; // Skip empty or whitespace-only lines

        const values = parseCsvRow(row);

        if (values.length > Math.max(stateIndex, descriptionIndex) && values[stateIndex] === 'Error') {
            const description = values[descriptionIndex] || '';
            const match = description.match(DESCRIPTION_REGEX);

            if (match && match.groups) {
                const { error_msg, filename, lines } = match.groups;
                const parsedLines = parseLineNumbers(lines);

                if (parsedLines.length > 0) {
                    errors.push({
                        errorMessage: error_msg.trim(),
                        filename: filename.trim(),
                        lines: parsedLines,
                    });
                } else if (error_msg.trim()){ // Still log if we got a message but no lines
                     errors.push({
                        errorMessage: error_msg.trim(),
                        filename: 'General Error',
                        lines: [],
                    });
                }
            } else {
                const errorMessage = description.trim();
                if (errorMessage) {
                    errors.push({
                        errorMessage: errorMessage,
                        filename: 'General Error',
                        lines: [],
                    });
                    warnings.push(`A general error was found with no specific file/line data: "${errorMessage}"`);
                }
            }
        }
    }
    return { errors, warnings };
};

const formatReport = (reportData: ReportData, warnings: string[]): string => {
    let reportString = '';
    const now = new Date();
    const timestamp = `${now.getFullYear()}-${(now.getMonth() + 1).toString().padStart(2, '0')}-${now.getDate().toString().padStart(2, '0')} ${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;

    reportString += `==================================================\n`;
    reportString += `ERROR REPORT GENERATED ON [${timestamp}]\n`;
    reportString += `==================================================\n\n`;

    if (warnings.length > 0) {
        reportString += `WARNINGS:\n`;
        warnings.forEach(w => {
            reportString += `- ${w}\n`;
        });
        reportString += `--------------------------------------------------\n\n`;
    }

    if (Object.keys(reportData).length === 0) {
        reportString += 'No reconcilable errors found in the provided files.\n';
        return reportString;
    }

    for (const errorMessage in reportData) {
        reportString += `[ERROR TYPE]: "${errorMessage}"\n`;
        reportString += `--------------------------------------------------\n`;
        const files = reportData[errorMessage];
        for (const filename in files) {
            reportString += `File: ${filename}\n`;
            const reconciledErrors = files[filename];
            if (reconciledErrors.length > 0) {
                reconciledErrors.forEach(({ lineNumber, rowData }) => {
                    reportString += `  Line ${lineNumber}:  ${rowData}\n`;
                });
            } else if (filename === 'General Error') {
                reportString += `  (This is a general error with no specific file or line number.)\n`;
            }
            reportString += `\n`;
        }
    }
    return reportString;
};

export const generateReport = async (logFile: File, sourceFiles: FileList): Promise<ReportOutput> => {
    const logContent = await readFileAsText(logFile);
    const { errors: parsedErrors, warnings: parsingWarnings } = parseLogCsv(logContent);

    const errorsByFile = parsedErrors.reduce((acc, error) => {
        if (!acc[error.filename]) {
            acc[error.filename] = [];
        }
        acc[error.filename].push(error);
        return acc;
    }, {} as { [filename: string]: ParsedLogError[] });

    const sourceFileMap = new Map<string, File>();
    for (let i = 0; i < sourceFiles.length; i++) {
        sourceFileMap.set(sourceFiles[i].name, sourceFiles[i]);
    }

    const reportData: ReportData = {};
    const warnings: string[] = [...parsingWarnings];

    for (const filename in errorsByFile) {
        if (filename === 'General Error') {
            const generalFileErrors = errorsByFile[filename];
            generalFileErrors.forEach(error => {
                if (!reportData[error.errorMessage]) {
                    reportData[error.errorMessage] = {};
                }
                reportData[error.errorMessage][filename] = []; 
            });
            continue;
        }

        const sourceFile = sourceFileMap.get(filename);
        if (!sourceFile) {
            warnings.push(`Source file "${filename}" mentioned in the log was not found.`);
            continue;
        }

        try {
            const sourceContent = await readFileAsText(sourceFile);
            const sourceLines = sourceContent.trim().split(/\r?\n/);
            const fileErrors = errorsByFile[filename];

            fileErrors.forEach(error => {
                if (!reportData[error.errorMessage]) {
                    reportData[error.errorMessage] = {};
                }
                if (!reportData[error.errorMessage][filename]) {
                    reportData[error.errorMessage][filename] = [];
                }

                error.lines.forEach(logLineNumber => {
                    // ASSUMPTION: The line number from the log file is a 1-based index
                    // that corresponds to the absolute line number in the source file
                    // (e.g., as seen in a text editor). This means if a source file has a
                    // header, the log's line numbers must account for it (e.g., the first
                    // data row would be line 2).

                    // To convert the 1-based log line number to a 0-based array index
                    // for `sourceLines`, we subtract 1.
                    const sourceLineIndex = logLineNumber - 1;

                    if (sourceLineIndex >= 0 && sourceLineIndex < sourceLines.length) {
                        reportData[error.errorMessage][filename].push({
                            lineNumber: logLineNumber, // Report the original line number from the log
                            rowData: sourceLines[sourceLineIndex].trim(),
                        });
                    } else {
                        warnings.push(`Line number ${logLineNumber} for file "${filename}" is out of range.`);
                    }
                });
            });

        } catch (e) {
            if (e instanceof Error) {
                warnings.push(`Could not read or process source file "${filename}": ${e.message}`);
            }
        }
    }

    const reportString = formatReport(reportData, warnings);

    return { reportString, reportData, warnings };
};
